@prefix cdifd: <https://cdif.org/validation/0.1/shacl#> .
@prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/complete-dataset-001> ;
            sh:resultMessage "other identifiers for the described resource" ;
            sh:resultPath schema1:sameAs ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:NodeKindConstraintComponent ;
            sh:sourceShape cdifd:otherIdentifierProperty ;
            sh:value [ a schema1:PropertyValue ;
                    schema1:value "urn:example:geochem:complete-001" ] ],
        [ a sh:ValidationResult ;
            sh:focusNode [ a schema1:LinkRole ;
                    schema1:linkRelationship [ a schema1:DefinedTerm ;
                            schema1:inDefinedTermSet "https://www.iana.org/assignments/link-relations/" ;
                            schema1:name "related dataset" ;
                            schema1:termCode "related" ] ] ;
            sh:resultMessage "a link to a related resource must specify the relationship to that resource, either with a string label or IRI" ;
            sh:resultPath schema1:linkRelationship ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:OrConstraintComponent ;
            sh:sourceShape [ sh:message "a link to a related resource must specify the relationship to that resource, either with a string label or IRI" ;
                    sh:minCount 1 ;
                    sh:or ( [ sh:nodeKind sh:IRI ] [ sh:datatype xsd:string ] ) ;
                    sh:path schema1:linkRelationship ] ;
            sh:value [ a schema1:DefinedTerm ;
                    schema1:inDefinedTermSet "https://www.iana.org/assignments/link-relations/" ;
                    schema1:name "related dataset" ;
                    schema1:termCode "related" ] ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/complete-dataset-001> ;
            sh:resultMessage "Contributors are expected to be assigned a role using the schema.org Role construct" ;
            sh:resultPath schema1:contributor ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:ClassConstraintComponent ;
            sh:sourceShape cdifd:contributorProperty ;
            sh:value <https://ror.org/03m2x1q45> ] .

